// Resolve Zendesk update fields
// Computes the scenario itself from category + full_refund + count (all knowable
// up front via absolute refs). For branches where the scenario depends on a late
// signal (cancellation rejection), an explicit `scenario` on the item wins.

const cfg = $('Get Project Config').first().json;
const req = $('Set request data test4').first().json;

const MAP = {
  TRIAL_ONLY:             { macro: 'refund_macro_trial_id',             category: 'refund_value_trial' },
  UPSELL_AND_TRIAL:       { macro: 'refund_macro_trial_id',             category: 'refund_value_trial' },
  RECURRENT_UPSELL_MULTI: { macro: 'refund_macro_monthly_legacy_id',    category: 'refund_value_monthly' },
  RECURRENT_UPSELL_SINGLE:{ macro: 'refund_macro_monthly_id',           category: 'refund_value_monthly' },
  RECURRENT_TRIAL:        { macro: 'refund_macro_monthly_id',           category: 'refund_value_monthly_alt' },
  RECURRENT_ONLY_LAST:    { macro: 'refund_macro_30day_last_charge_id', category: 'refund_value_30day_last_charge_alt' },
  RECURRENT_ONLY_TWO:     { macro: 'refund_macro_30day_two_charges_id', category: 'refund_value_30day_two_charges' },
  ALL_LAST_CHARGE:        { macro: 'refund_macro_30day_last_charge_id', category: 'refund_value_30day_last_charge' },
  ALL_TWO_CHARGES:        { macro: 'refund_macro_30day_two_charges_id', category: 'refund_value_monthly' },
  ONE_TXN_MONTHLY:        { macro: 'refund_macro_monthly_id',           category: 'refund_value_30day_last_charge_alt' },
  REJECTION:              { macro: 'refund_macro_rejection_id',         category: 'refund_value_rejection' },
  REJECTION_PAST_REFUNDS: { macro: 'macro_rejection_with_past_refunds', category: 'refund_value_rejection' },
};

function inferScenario() {
  const category   = $('Categorise request based on transaction types').first().json.transactionCategory;
  const fullRefund = req.original_ticket_content.full_refund_request === true;
  const txns       = $('Redirect based on last transactions').first().json.body.transactions || [];
  const multi      = txns.length > 1;

  switch (category) {
    case 'CAT__TRIAL_ONLY':          return 'TRIAL_ONLY';
    case 'CAT__UPSELL_AND_TRIAL':    return 'UPSELL_AND_TRIAL';
    case 'CAT__RECURRENT_AND_TRIAL': return 'RECURRENT_TRIAL';
    case 'CAT__RECURRENT_AND_UPSELL':
      return (fullRefund && multi) ? 'RECURRENT_UPSELL_SINGLE' : 'RECURRENT_UPSELL_MULTI';
    case 'CAT__RECURRENT_ONLY':
      // full refund: >1 -> two charges, exactly 1 -> last charge
      if (fullRefund) return multi ? 'RECURRENT_ONLY_TWO' : 'RECURRENT_ONLY_LAST';
      // partial refund (corrected): >1 -> last charge, exactly 1 -> monthly
      return multi ? 'RECURRENT_ONLY_LAST' : 'ONE_TXN_MONTHLY';
    case 'CAT__ALL_THREE_PRESENT':
      return (fullRefund && multi) ? 'ALL_TWO_CHARGES' : 'ALL_LAST_CHARGE';
    default:
      throw new Error(`Resolve: cannot infer scenario for category '${category}' (pass an explicit scenario)`);
  }
}

return $input.all().map(item => {
  const scenario = item.json.scenario ?? inferScenario();
  const m = MAP[scenario];
  if (!m) throw new Error(`Resolve: unknown scenario '${scenario}'`);

  return {
    json: {
      zendeskDomain:          cfg.zendesk_domain,
      ticketID:               req.original_ticket_content.ticket_id,
      isTranslated:           req.translated_data.is_translated,
      originalLanguage:       req.translated_data.originalLanguage,
      ticketCustomFieldID:    cfg.ticket_custom_field_category,
      publicComment:          item.json.publicComment ?? true,
      ticketCustomStatusID:   cfg[item.json.statusKey ?? 'ticket_custom_status_solved_id'],
      macroID:                cfg[m.macro],
      ticketCustomFieldValue: cfg[m.category],
      scenario,
    },
  };
});
